import { reportWebVitals } from 'web-vitals';

export function sendToAnalytics(metric) {
  const { id, name, value } = metric;
  console.log(`Sending metric ${name} (${id}) to analytics: ${value}`);
}

reportWebVitals(sendToAnalytics);

/* General Styles */

body {
  font-family: Arial, sans-serif;
  background-color: #f0f0f0;
  margin: 0;
  padding: 0;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 20px;
}

/* Header Styles */

header {
  background-color: #333;
  color: #fff;
  padding: 20px;
}

/* Footer Styles */

footer {
  background-color: #333;
  color: #fff;
  padding: 20px;
  text-align: center;
}

/* Button Styles */

.button {
  background-color: #333;
  color: #fff;
  border: none;
  padding: 10px 20px;
  font-size: 16px;
  cursor: pointer;
}

/* Card Styles */

.card {
  background-color: #fff;
  color: #333;
  border-radius: 5px;
  padding: 20px;
  margin-bottom: 20px;
}

.card h2 {
  margin-top: 0;
}

.card p {
  margin-bottom: 0;
}

